   321→async function getReviewThreads(
   322→  prNumber: number,
   323→  filterReviewIds?: number[]
   324→): Promise<Array<{ id: string; path: string; line: number }>> {
   325→  const query = `
   326→    query GetReviewThreads($owner: String!, $repo: String!, $pr: Int!) {
   327→      repository(owner: $owner, name: $repo) {
   328→        pullRequest(number: $pr) {
   329→          reviewThreads(last: 100) {
   330→            nodes {
   331→              id
   332→              isResolved
   333→              path
   334→              line
   335→              comments(first: 1) {
   336→                nodes {
   337→                  pullRequestReview {
   338→                    databaseId
   339→                  }
   340→                }
   341→              }
   342→            }
   343→          }
   344→        }
   345→      }
   346→    }
   347→  `;
   348→
   349→  // Get owner and repo from gh
   350→  const repoResult = await runCommand([
   351→    "gh",
   352→    "repo",
   353→    "view",
   354→    "--json",
   355→    "owner,name",
   356→  ]);
   357→  if (repoResult.exitCode !== 0) return [];
   358→
   359→  const repoInfo = JSON.parse(repoResult.stdout);
   360→  const owner = repoInfo.owner.login;
   361→  const repo = repoInfo.name;
   362→
   363→  const result = await runCommand([
   364→    "gh",
   365→    "api",
   366→    "graphql",
   367→    "-f",
   368→    `query=${query}`,
   369→    "-f",
   370→    `owner=${owner}`,
   371→    "-f",
   372→    `repo=${repo}`,
   373→    "-F",
   374→    `pr=${prNumber}`,
   375→  ]);
   376→
   377→  if (result.exitCode !== 0) return [];
   378→
   379→  try {
   380→    const data = JSON.parse(result.stdout);
   381→    const threads = data.data.repository.pullRequest.reviewThreads.nodes;
   382→    return threads
   383→      .filter((t: { isResolved: boolean }) => !t.isResolved)
   384→      .filter((t: { comments: { nodes: Array<{ pullRequestReview?: { databaseId?: number } }> } }) => {
   385→        if (!filterReviewIds || filterReviewIds.length === 0) return true;
   386→        const reviewId = t.comments.nodes[0]?.pullRequestReview?.databaseId;
   387→        return reviewId != null && filterReviewIds.includes(reviewId);
   388→      })
   389→      .map((t: { id: string; path: string; line: number }) => ({
   390→        id: t.id,
   391→        path: t.path,
   392→        line: t.line,
   393→      }));
   394→  } catch {
   395→    return [];
   396→  }
   397→}
   398→
   399→export async function submitReview(
   400→  prNumber: number,
   401→  result: ReviewResult,
   402→  diffFindings: Finding[],
   403→  generalFindings: Finding[],
   404→  dryRun = false,
   405→  logger?: Logger
   406→): Promise<{ success: boolean; failedFindings: Finding[]; reviewUrl?: string }> {
   407→  const tracer = getTracer();
   408→
   409→  return withSpan(tracer, "submitReview", async () => {
   410→    const failedFindings: Finding[] = [];
   411→
   412→    // Build review comments from diff findings
   413→    const comments: ReviewComment[] = [];
   414→    const fulfilledComments: Array<{ path: string; line: number }> = [];
   415→
   416→    for (const finding of diffFindings) {
   417→      const comment = buildReviewComment(finding);
   418→      if (comment) {
   419→        comments.push(comment);
   420→        if (finding.status === "fulfilled") {
   421→          fulfilledComments.push({ path: comment.path, line: comment.line });
   422→        }
   423→      } else {
   424→        failedFindings.push(finding);
   425→      }
   426→    }
   427→
   428→    // Build review body from general findings and summary
   429→    const reviewBody = formatReviewBody(result, generalFindings);
   430→
   431→    if (dryRun) {
   432→      logger?.info("Dry run - would submit review", { commentCount: comments.length });
   433→      console.log(`[DRY RUN] Would submit review with ${comments.length} diff comment(s)`);
   434→      for (const comment of comments) {
   435→        console.log(`  - ${comment.path}:${comment.line}`);
   436→      }
   437→      console.log(`[DRY RUN] Review body preview: ${reviewBody.slice(0, 200)}...`);
   438→      if (fulfilledComments.length > 0) {
   439→        console.log(`[DRY RUN] Would resolve ${fulfilledComments.length} fulfilled comment(s)`);
   440→      }
   441→      console.log(`[DRY RUN] Would archive previous Vibereq reviews`);
   442→      return { success: true, failedFindings };
   443→    }
   444→
   445→    const commitSha = await getCommitSha(prNumber, logger);
   446→    if (!commitSha) {
   447→      return { success: false, failedFindings: [...diffFindings, ...generalFindings] };
   448→    }
   449→
   450→    // Build the review payload
   451→    const payload: Record<string, unknown> = {
   452→      commit_id: commitSha,
   453→      body: reviewBody,
   454→      event: "COMMENT",
   455→    };
   456→
   457→    if (comments.length > 0) {
   458→      payload.comments = comments;
   459→    }
   460→
   461→    // Write payload to temp file for gh api
   462→    const tempFile = `/tmp/vibx-review-${Date.now()}.json`;
   463→    await Bun.write(tempFile, JSON.stringify(payload));
   464→
   465→    const createResult = await withSpan(tracer, "gh.api.createReview", () => runCommand([
   466→      "gh",
   467→      "api",
   468→      "-X",
   469→      "POST",
   470→      `/repos/{owner}/{repo}/pulls/${prNumber}/reviews`,
   471→      "--input",
   472→      tempFile,
   473→    ]));
   474→
   475→    // Clean up temp file
   476→    try {
   477→      if (await Bun.file(tempFile).exists()) {
   478→        await runCommand(["rm", tempFile]);
   479→      }
   480→    } catch {
   481→      // Ignore cleanup errors
   482→    }
   483→
   484→    if (createResult.exitCode !== 0) {
   485→      logger?.error("Failed to create review", { prNumber, stderr: createResult.stderr });
   486→      return { success: false, failedFindings: [...diffFindings, ...generalFindings] };
   487→    }
   488→
   489→    // Extract the new review ID and URL from the response
   490→    let reviewUrl: string | undefined;
   491→    let reviewId: number | undefined;
   492→    try {
   493→      const reviewData = JSON.parse(createResult.stdout);
   494→      reviewUrl = reviewData.html_url;
   495→      reviewId = reviewData.id;
   496→    } catch {
   497→      logger?.warn("Could not extract review data from response");
   498→    }
   499→
   500→    logger?.info("Created review", { prNumber, commentCount: comments.length, reviewUrl, reviewId });
   501→    console.log(`Created review with ${comments.length} diff comment(s)`);
   502→
   503→    // Archive previous Vibereq reviews (exclude the one we just created)
   504→    if (reviewUrl && reviewId) {
   505→      await archivePreviousReviews(prNumber, reviewUrl, reviewId, logger);
   506→    }
   507→
   508→    // Resolve fulfilled comments from the NEW review
   509→    if (fulfilledComments.length > 0) {
   510→      console.log(`Resolving ${fulfilledComments.length} fulfilled comment(s)...`);
   511→      const threads = await getReviewThreads(prNumber);
   512→
   513→      for (const fulfilled of fulfilledComments) {
   514→        const thread = threads.find(
   515→          (t) => t.path === fulfilled.path && t.line === fulfilled.line
   516→        );
   517→        if (thread) {
   518→          const resolved = await resolveReviewThread(thread.id);
   519→          if (resolved) {
