import type { ProcessResult } from "../types.js";

const CHECKPOINT_RE = /^\s*Entire-Checkpoint:\s*([0-9a-fA-F]+)\s*$/m;
export const CHECKPOINT_BRANCH = "entire/checkpoints/v1";

export async function hasUncommittedChanges(): Promise<boolean> {
  const { stdout, exitCode } = await runGit(["status", "--porcelain"]);
  if (exitCode !== 0) return false;
  return stdout.trim().length > 0;
}

export async function stageAllChanges(): Promise<void> {
  const { exitCode, stderr } = await runGit(["add", "-A"]);
  if (exitCode !== 0) {
    throw new Error(`Failed to stage changes: ${stderr}`);
  }
}

export async function createCommit(message: string): Promise<void> {
  const { exitCode, stderr } = await runGit(["commit", "-m", message]);
  if (exitCode !== 0) {
    throw new Error(`Failed to create commit: ${stderr}`);
  }
}

export async function getCurrentBranch(): Promise<string> {
  const { stdout, exitCode, stderr } = await runGit([
    "rev-parse",
    "--abbrev-ref",
    "HEAD",
  ]);
  if (exitCode !== 0) {
    throw new Error(`Failed to get current branch: ${stderr}`);
  }
  return stdout.trim();
}

export async function hasRemoteTracking(branch: string): Promise<boolean> {
  const { exitCode } = await runGit([
    "rev-parse",
    "--abbrev-ref",
    `${branch}@{upstream}`,
  ]);
  return exitCode === 0;
}

export async function pushWithUpstream(branch: string): Promise<void> {
  const { exitCode, stderr } = await runGit([
    "push",
    "-u",
    "origin",
    branch,
  ]);
  if (exitCode !== 0) {
    throw new Error(`Failed to push: ${stderr}`);
  }
}

export async function getDiff(base = "main"): Promise<string> {
  const { stdout, exitCode } = await runGit(["diff", `${base}...HEAD`]);
  if (exitCode !== 0) return "";
  return stdout;
}

export async function getStagedDiff(): Promise<string> {
  const { stdout, exitCode } = await runGit(["diff", "--staged"]);
  if (exitCode !== 0) return "";
  return stdout;
}

export async function runGit(args: string[]): Promise<ProcessResult> {
  const proc = Bun.spawn(["git", ...args], {
    stdout: "pipe",
    stderr: "pipe",
  });
  const stdout = await new Response(proc.stdout).text();
  const stderr = await new Response(proc.stderr).text();
  const exitCode = await proc.exited;
  return { stdout, stderr, exitCode };
}

export async function getCommitsNotInMain(): Promise<string[]> {
  const { stdout, exitCode } = await runGit([
    "rev-parse",
    "--is-inside-work-tree",
  ]);
  if (exitCode !== 0 || stdout.trim() !== "true") {
    throw new Error("Not inside a git repository.");
  }

  const tryLog = async (base: string): Promise<string[] | null> => {
    const result = await runGit(["log", `${base}..HEAD`, "--format=%H"]);
    if (result.exitCode === 0) {
      return result.stdout
        .split("\n")
        .map((l) => l.trim())
        .filter(Boolean);
    }
    return null;
  };

  let commits = await tryLog("main");
  if (commits === null) commits = await tryLog("origin/main");
  if (commits === null) commits = await tryLog("HEAD~0");
  if (commits === null) {
    throw new Error("Unable to compute commits not in main.");
  }
  return commits;
}

export async function getCheckpointHash(
  commitHash: string
): Promise<string | null> {
  const { stdout, exitCode } = await runGit([
    "log",
    "-1",
    "--format=%B",
    commitHash,
  ]);
  if (exitCode !== 0) return null;
  const match = CHECKPOINT_RE.exec(stdout);
  return match ? match[1].toLowerCase() : null;
}

export function checkpointHashToFolder(hash: string): string {
  const h = hash.trim().toLowerCase();
  if (h.length < 3) {
    return `${h}/${h}/0`;
  }
  return `${h.slice(0, 2)}/${h.slice(2)}/0`;
}

export async function fileExistsOnBranch(
  branch: string,
  path: string
): Promise<boolean> {
  const spec = `${branch}:${path}`;
  const { exitCode } = await runGit(["cat-file", "-e", spec]);
  return exitCode === 0;
}

export async function showFile(
  branch: string,
  path: string
): Promise<string | null> {
  const spec = `${branch}:${path}`;
  const { stdout, exitCode } = await runGit(["show", spec]);
  if (exitCode !== 0) return null;
  return stdout;
}

export async function commitToCheckpointBranch(
  folder: string,
  content: string
): Promise<string> {
  const relPath = `${folder}/intent.md`;

  // 1. Create blob from intent content
  const blobProc = Bun.spawn(["git", "hash-object", "-w", "--stdin"], {
    stdin: new Response(content),
    stdout: "pipe",
    stderr: "pipe",
  });
  const blobStdout = await new Response(blobProc.stdout).text();
  const blobStderr = await new Response(blobProc.stderr).text();
  if ((await blobProc.exited) !== 0) {
    throw new Error(`Failed to create blob: ${blobStderr}`);
  }
  const blobHash = blobStdout.trim();

  // 2. Create a temporary index file
  const tmpIndex = `/tmp/vibx-git-index-${Date.now()}`;
  const env = { ...process.env, GIT_INDEX_FILE: tmpIndex };

  try {
    // Read current tree from checkpoint branch into temp index
    const readTreeProc = Bun.spawn(["git", "read-tree", CHECKPOINT_BRANCH], {
      env,
      stdout: "pipe",
      stderr: "pipe",
    });
    const readTreeStderr = await new Response(readTreeProc.stderr).text();
    if ((await readTreeProc.exited) !== 0) {
      throw new Error(`Failed to read tree: ${readTreeStderr}`);
    }

    // Add new file to index
    const updateIndexProc = Bun.spawn(
      [
        "git",
        "update-index",
        "--add",
        "--cacheinfo",
        `100644,${blobHash},${relPath}`,
      ],
      { env, stdout: "pipe", stderr: "pipe" }
    );
    const updateIndexStderr = await new Response(updateIndexProc.stderr).text();
    if ((await updateIndexProc.exited) !== 0) {
      throw new Error(`Failed to update index: ${updateIndexStderr}`);
    }

    // Write tree
    const writeTreeProc = Bun.spawn(["git", "write-tree"], {
      env,
      stdout: "pipe",
      stderr: "pipe",
    });
    const writeTreeStdout = await new Response(writeTreeProc.stdout).text();
    const writeTreeStderr = await new Response(writeTreeProc.stderr).text();
    if ((await writeTreeProc.exited) !== 0) {
      throw new Error(`Failed to write tree: ${writeTreeStderr}`);
    }
    const newTree = writeTreeStdout.trim();

    // Get parent commit
    const { stdout: parentStdout, exitCode: parentExitCode } = await runGit([
      "rev-parse",
      CHECKPOINT_BRANCH,
    ]);
    if (parentExitCode !== 0) {
      throw new Error("Failed to get parent commit");
    }
    const parent = parentStdout.trim();

    // Create commit
    const commitProc = Bun.spawn(
      [
        "git",
        "commit-tree",
        newTree,
        "-p",
        parent,
        "-m",
        `Add intent for ${folder}`,
      ],
      { stdout: "pipe", stderr: "pipe" }
    );
    const commitStdout = await new Response(commitProc.stdout).text();
    const commitStderr = await new Response(commitProc.stderr).text();
    if ((await commitProc.exited) !== 0) {
      throw new Error(`Failed to create commit: ${commitStderr}`);
    }
    const newCommit = commitStdout.trim();

    // Update branch reference
    const { exitCode: updateRefExitCode } = await runGit([
      "update-ref",
      `refs/heads/${CHECKPOINT_BRANCH}`,
      newCommit,
    ]);
    if (updateRefExitCode !== 0) {
      throw new Error("Failed to update branch");
    }

    return relPath;
  } finally {
    // Clean up temp index
    try {
      await Bun.file(tmpIndex).delete();
    } catch {
      // Ignore cleanup errors
    }
  }
}

import type { AppContext } from "../lib/context.js";
import { withSpan } from "../lib/observability.js";
import type { PrOptions, PrResult } from "../types.js";
import {
  hasUncommittedChanges,
  stageAllChanges,
  createCommit,
  getCurrentBranch,
  hasRemoteTracking,
  pushWithUpstream,
  getStagedDiff,
} from "../lib/git.js";
import { getCurrentPR, createPR, getPRUrl } from "../lib/github.js";
import { processIntents } from "./intent.js";
import { handler as reviewHandler } from "./review.js";

const COMMIT_PROMPT = `You are a commit message generator. Given the diff below, generate a conventional commit message.

Rules:
- Use conventional commit format: type(scope): description
- Types: feat, fix, refactor, docs, test, chore, style, perf
- Keep the first line under 72 characters
- Be concise and descriptive
- Output ONLY the commit message, nothing else

Diff:
`;

async function generateCommitMessage(diff: string): Promise<string> {
  const proc = Bun.spawn(
    ["claude", "-p", COMMIT_PROMPT + diff, "--model", "claude-haiku-4-5-20251001"],
    {
      stdout: "pipe",
      stderr: "pipe",
      env: Object.fromEntries(
        Object.entries(process.env).filter(([k]) => k !== "CLAUDECODE")
      ),
    }
  );

  const stdout = await new Response(proc.stdout).text();
  const exitCode = await proc.exited;

  if (exitCode !== 0) {
    // Fallback to pattern-based message
    return "chore: update codebase";
  }

  return stdout.trim().split("\n")[0]; // First line only
}

export async function processPr(
  ctx: AppContext,
  options: PrOptions = {}
): Promise<PrResult> {
  return withSpan(ctx.tracer, "processPr", async () => {
    const result: PrResult = {
      success: false,
      committed: false,
      intentGenerated: false,
      reviewPosted: false,
      errors: [],
    };

    const dryRun = options.dryRun ?? false;
    const skipReview = options.skipReview ?? false;
    const base = options.base ?? "main";

    // Step 1: Commit if there are changes
    const hasChanges = await hasUncommittedChanges();
    if (hasChanges) {
      ctx.logger.info("Uncommitted changes detected, creating commit");
      console.log("Uncommitted changes detected, creating commit...");

      try {
        await stageAllChanges();
        const diff = await getStagedDiff();
        const message = await generateCommitMessage(diff);

        if (dryRun) {
          console.log(`[DRY RUN] Would commit with message: ${message}`);
        } else {
          await createCommit(message);
          console.log(`Committed: ${message}`);
        }
        result.committed = true;
      } catch (e) {
        const error = `Failed to commit: ${e instanceof Error ? e.message : e}`;
        ctx.logger.error("Commit failed", { error: e });
        result.errors.push(error);
        console.error(error);
        // Continue anyway - maybe there were no changes to commit
      }
    } else {
      ctx.logger.info("No uncommitted changes");
      console.log("No uncommitted changes to commit.");
    }

    // Step 2: Generate intent
    ctx.logger.info("Generating intents");
    console.log("Generating intents...");

    try {
      const intentResult = await processIntents(ctx);
      if (intentResult.success) {
        result.intentGenerated = true;
        console.log(`Generated ${intentResult.results.length} intent(s)`);
      } else {
        for (const error of intentResult.errors) {
          console.error(error);
        }
        // Don't fail - continue to PR creation
      }
    } catch (e) {
      const error = `Intent generation failed: ${e instanceof Error ? e.message : e}`;
      ctx.logger.warn("Intent generation failed", { error: e });
      result.errors.push(error);
      console.error(error);
    }

    // Step 3: Push and create PR
    const branch = await getCurrentBranch();
    const hasTracking = await hasRemoteTracking(branch);

    if (!hasTracking || !(await getCurrentPR())) {
      ctx.logger.info("Pushing branch", { branch });
      console.log(`Pushing branch ${branch}...`);

      if (!dryRun) {
        try {
          await pushWithUpstream(branch);
          console.log("Pushed to remote");
        } catch (e) {
          const error = `Push failed: ${e instanceof Error ? e.message : e}`;
          ctx.logger.error("Push failed", { error: e });
          result.errors.push(error);
          console.error(error);
          return result;
        }
      } else {
        console.log(`[DRY RUN] Would push branch ${branch}`);
      }
    }

    // Check if PR exists
    let prNumber = await getCurrentPR();
    let prUrl: string | null = null;

    if (!prNumber) {
      ctx.logger.info("Creating PR");
      console.log("Creating PR...");

      if (!dryRun) {
        const prResult = await createPR();
        if (prResult) {
          prNumber = prResult.number;
          prUrl = prResult.url;
          console.log(`Created PR #${prNumber}: ${prUrl}`);
        } else {
          const error = "Failed to create PR";
          ctx.logger.error(error);
          result.errors.push(error);
          console.error(error);
          return result;
        }
      } else {
        console.log("[DRY RUN] Would create PR");
      }
    } else {
      prUrl = await getPRUrl(prNumber);
      console.log(`Using existing PR #${prNumber}`);
    }

    result.prNumber = prNumber ?? undefined;
    result.prUrl = prUrl ?? undefined;

    // Step 4: Run review
    if (!skipReview && prNumber) {
      ctx.logger.info("Running code review", { prNumber });
      console.log("Running code review...");

      try {
        await reviewHandler(ctx, {
          skill: "vibereq:code-review",
          pr: prNumber,
          dryRun,
          base,
        });
        result.reviewPosted = true;
      } catch (e) {
        const error = `Review failed: ${e instanceof Error ? e.message : e}`;
        ctx.logger.error("Review failed", { error: e });
        result.errors.push(error);
        console.error(error);
        // Don't fail completely - PR was created
      }
    }

    result.success = true;
    ctx.logger.info("PR processing complete", {
      prNumber: result.prNumber,
      committed: result.committed,
      intentGenerated: result.intentGenerated,
      reviewPosted: result.reviewPosted,
    });

    if (prUrl) {
      console.log(`\nPR: ${prUrl}`);
    }

    return result;
  });
}

export async function handler(ctx: AppContext, options: PrOptions = {}): Promise<void> {
  ctx.logger.debug("Starting pr command");

  const result = await processPr(ctx, options);

  if (!result.success) {
    process.exit(1);
  }
}

